namespace sv_b7bc172c86814134957fa35b4ef9c61b;

// Domain records
public record JobApplication(PersonalInfo Personal, WorkHistory Work, List<Reference> References, string CoverLetter);
public record PersonalInfo(string FullName, string Email, string Phone, string Address);
public record WorkHistory(List<WorkEntry> Entries);
public record WorkEntry(string Company, string Title, DateTime StartDate, DateTime? EndDate, string Description);
public record Reference(string Name, string Relationship, string Email, string Phone);

public interface IApplicationService
{
    Task<int> SubmitApplicationAsync(JobApplication application);
    Task<bool> ValidateEmailAsync(string email);
}

// Mutable form models for two-way binding
public class PersonalInfoModel
{
    public string FullName { get; set; } = "";
    public string Email { get; set; } = "";
    public string Phone { get; set; } = "";
    public string Address { get; set; } = "";

    public PersonalInfo ToRecord() => new(FullName, Email, Phone, Address);
}

public class WorkEntryModel
{
    public string Company { get; set; } = "";
    public string Title { get; set; } = "";
    public DateTime? StartDate { get; set; }
    public DateTime? EndDate { get; set; }
    public bool IsCurrent { get; set; }
    public string Description { get; set; } = "";

    public WorkEntry ToRecord() => new(Company, Title, StartDate ?? DateTime.Today, IsCurrent ? null : EndDate, Description);
}

public class ReferenceModel
{
    public string Name { get; set; } = "";
    public string Relationship { get; set; } = "";
    public string Email { get; set; } = "";
    public string Phone { get; set; } = "";

    public Reference ToRecord() => new(Name, Relationship, Email, Phone);
}

@* Step progress bar showing all 5 steps with current/completed/future states *@

<nav class="step-indicator mb-4" aria-label="Application progress">
    <ol class="step-list">
        @for (int i = 0; i < StepLabels.Length; i++)
        {
            var stepNumber = i + 1;
            var state = GetStepState(stepNumber);
            <li class="step-item @state" @onclick="() => OnStepClick(stepNumber)" role="button"
                aria-current="@(stepNumber == CurrentStep ? "step" : null)">
                <span class="step-circle">
                    @if (stepNumber < CurrentStep)
                    {
                        <span class="step-check">✓</span>
                    }
                    else
                    {
                        @stepNumber
                    }
                </span>
                <span class="step-label">@StepLabels[i]</span>
            </li>
        }
    </ol>
</nav>

@code {
    private static readonly string[] StepLabels =
        ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];

    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter] public EventCallback<int> OnStepSelected { get; set; }

    private string GetStepState(int step) =>
        step == CurrentStep ? "active" :
        step < CurrentStep ? "completed" :
        "future";

    private async Task OnStepClick(int step)
    {
        // Only allow clicking completed steps
        if (step < CurrentStep)
        {
            await OnStepSelected.InvokeAsync(step);
        }
    }
}

.step-indicator {
    width: 100%;
}

.step-list {
    display: flex;
    list-style: none;
    padding: 0;
    margin: 0;
    counter-reset: step;
}

.step-item {
    flex: 1;
    display: flex;
    flex-direction: column;
    align-items: center;
    position: relative;
    cursor: default;
}

.step-item.completed {
    cursor: pointer;
}

.step-item::after {
    content: '';
    position: absolute;
    top: 18px;
    left: 50%;
    width: 100%;
    height: 2px;
    background-color: #dee2e6;
    z-index: 0;
}

.step-item:last-child::after {
    display: none;
}

.step-item.completed::after {
    background-color: #0d6efd;
}

.step-item.active::after {
    background: linear-gradient(to right, #0d6efd 0%, #dee2e6 100%);
}

.step-circle {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 600;
    font-size: 0.875rem;
    z-index: 1;
    border: 2px solid #dee2e6;
    background-color: #fff;
    color: #6c757d;
    transition: all 0.2s ease;
}

.step-item.active .step-circle {
    border-color: #0d6efd;
    background-color: #0d6efd;
    color: #fff;
}

.step-item.completed .step-circle {
    border-color: #0d6efd;
    background-color: #0d6efd;
    color: #fff;
}

.step-check {
    font-size: 1rem;
}

.step-label {
    margin-top: 0.5rem;
    font-size: 0.75rem;
    text-align: center;
    color: #6c757d;
}

.step-item.active .step-label {
    color: #0d6efd;
    font-weight: 600;
}

.step-item.completed .step-label {
    color: #212529;
}

.step-item.future .step-label {
    color: #adb5bd;
}

