toolArgs.file_text:
.step-indicator {
    width: 100%;
}

.step-list {
    display: flex;
    list-style: none;
    padding: 0;
    margin: 0;
    counter-reset: step;
}

.step-item {
    flex: 1;
    display: flex;
    flex-direction: column;
    align-items: center;
    position: relative;
    cursor: default;
}

.step-item.completed {
    cursor: pointer;
}

.step-item::after {
    content: '';
    position: absolute;
    top: 18px;
    left: 50%;
    width: 100%;
    height: 2px;
    background-color: #dee2e6;
    z-index: 0;
}

.step-item:last-child::after {
    display: none;
}

.step-item.completed::after {
    background-color: #0d6efd;
}

.step-item.active::after {
    background: linear-gradient(to right, #0d6efd 0%, #dee2e6 100%);
}

.step-circle {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 600;
    font-size: 0.875rem;
    z-index: 1;
    border: 2px solid #dee2e6;
    background-color: #fff;
    color: #6c757d;
    transition: all 0.2s ease;
}

.step-item.active .step-circle {
    border-color: #0d6efd;
    background-color: #0d6efd;
    color: #fff;
}

.step-item.completed .step-circle {
    border-color: #0d6efd;
    background-color: #0d6efd;
    color: #fff;
}

.step-check {
    font-size: 1rem;
}

.step-label {
    margin-top: 0.5rem;
    font-size: 0.75rem;
    text-align: center;
    color: #6c757d;
}

.step-item.active .step-label {
    color: #0d6efd;
    font-weight: 600;
}

.step-item.completed .step-label {
    color: #212529;
}

.step-item.future .step-label {
    color: #adb5bd;
}

